def checkout_process(cart_items, discount_code, user, payment_info):
    if not validate_cart_items(cart_items):
        return 'Invalid cart items'
    
    cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
    cart_total = apply_discount_codes(cart_total, discount_code, user)
    tax = calculate_tax(cart_total)
    cart_total += tax
    
    if not process_payment(cart_total, payment_info):
        return 'Payment failed'
    
    order = create_order_record(cart_items, user, cart_total)
    return order

